var symbols = ($.input.stockSymbols || '').split(',').map(function(s) { return s.trim(); }).filter(function(s) { return s.length > 0; });
var query = 'stock market analysis ' + symbols.join(' ') + ' latest news forecast';
return { query: query, symbols: symbols };

var results = $.steps.searchMarketNews.response.results || [];
var newsText = '';
results.forEach(function(r, i) {
  newsText += 'SOURCE ' + (i + 1) + ': ' + (r.title || '') + '\n';
  newsText += 'URL: ' + (r.url || '') + '\n';
  newsText += 'Date: ' + (r.publishedDate || '') + '\n';
  newsText += (r.text || '').slice(0, 1500) + '\n\n';
});
return { newsText: newsText, sourceCount: results.length };

var data = $.steps.compileNews.output;
var symbols = $.steps.buildQuery.output.symbols;
var prompt = 'You are a professional financial analyst. Analyze the following market news and provide investment insights.

';
prompt += 'STOCKS TO ANALYZE: ' + symbols.join(', ') + '
';
prompt += 'INVESTMENT STYLE: ' + ($.input.investmentStyle || 'moderate growth') + '

';
prompt += 'MARKET NEWS (' + data.sourceCount + ' sources):
' + data.newsText + '
';
prompt += 'DISCLAIMER: This is for educational purposes only, not financial advice.

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Analyze market sentiment for each stock
';
prompt += '- Identify key trends, risks, and catalysts
';
prompt += '- Provide a sentiment score (-100 to +100) for each
';
prompt += '- Generate actionable insights aligned with the investment style

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "marketOverview": "Brief overall market assessment",
';
prompt += '  "stocks": [
';
prompt += '    {
';
prompt += '      "symbol": "AAPL",
';
prompt += '      "sentiment": 65,
';
prompt += '      "signal": "Buy|Hold|Sell|Watch",
';
prompt += '      "analysis": "Key analysis for this stock",
';
prompt += '      "catalysts": ["catalyst1"],
';
prompt += '      "risks": ["risk1"],
';
prompt += '      "priceTarget": "estimated direction"
';
prompt += '    }
';
prompt += '  ],
';
prompt += '  "topPick": "SYMBOL",
';
prompt += '  "sectorTrends": ["trend1"],
';
prompt += '  "disclaimer": "Not financial advice"
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiAnalyze.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { marketOverview: raw, stocks: [], topPick: '', sectorTrends: [], disclaimer: 'Not financial advice' }; }

var ai = $.steps.parseAI.output;
var stocks = ai.stocks || [];
var date = new Date().toISOString().split('T')[0];
var sheetData = stocks.map(function(s) {
  return {
    'Date': date,
    'Symbol': s.symbol || '',
    'Sentiment': s.sentiment || '',
    'Signal': s.signal || '',
    'Analysis': (s.analysis || '').slice(0, 300),
    'Catalysts': (s.catalysts || []).join('; '),
    'Risks': (s.risks || []).join('; '),
    'Price Target': s.priceTarget || '',
    'Style': $.input.investmentStyle || 'moderate growth'
  };
});
return { sheetData: sheetData, stockCount: stocks.length, date: date };

var ai = $.steps.parseAI.output;
var stocks = ai.stocks || [];
var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Market Analysis Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Overview:* ' + (ai.marketOverview || '').slice(0, 500) } });
if (ai.topPick) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Top Pick:* ' + ai.topPick } });
}
blocks.push({ type: 'divider' });
stocks.forEach(function(s) {
  var emoji = ':white_check_mark:';
  if (s.signal === 'Sell') emoji = ':x:';
  if (s.signal === 'Hold') emoji = ':pause_button:';
  if (s.signal === 'Watch') emoji = ':eyes:';
  var text = emoji + ' *' + s.symbol + '* | Signal: ' + (s.signal || '') + ' | Sentiment: ' + (s.sentiment || '') + '/100';
  text += '\n' + (s.analysis || '').slice(0, 300);
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text } });
});
blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':warning: ' + (ai.disclaimer || 'Not financial advice') + ' | Analyzed with Claude AI via One CLI' }] });
var fallback = 'Market Analysis: ' + stocks.length + ' stocks analyzed - Top pick: ' + (ai.topPick || 'N/A');
return { blocks: blocks, fallback: fallback };
